const parseConditionalJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema)) return
	if (!("then" in jsonSchema) && !("else" in jsonSchema)) return
	const ifSchema = jsonSchemaToType(jsonSchema.if)
	const thenSchema =
		"then" in jsonSchema ? jsonSchemaToType(jsonSchema.then) : undefined
	const elseSchema =
		"else" in jsonSchema ? jsonSchemaToType(jsonSchema.else) : undefined
	return type.unknown.narrow((data, ctx) => {
		const branch = ifSchema.allows(data) ? thenSchema : elseSchema
		return !branch || branch.allows(data) ?
				true
			:	ctx.reject({
					expected: `valid according to conditional ${ifSchema.allows(data) ? "then" : "else"} schema`,
					actual: printable(data)
				})
	})
}

export const parseCompositionJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	const validators: Type[] = []
	if ("allOf" in jsonSchema)
		validators.push(parseAllOfJsonSchema(jsonSchema.allOf))
	if ("anyOf" in jsonSchema)
		validators.push(parseAnyOfJsonSchema(jsonSchema.anyOf))
	if ("not" in jsonSchema) validators.push(parseNotJsonSchema(jsonSchema.not))
	if ("oneOf" in jsonSchema)
		validators.push(parseOneOfJsonSchema(jsonSchema.oneOf))
	const conditional = parseConditionalJsonSchema(jsonSchema)
	if (conditional) validators.push(conditional)
	return validators.reduce<Type | undefined>(
		(acc, validator) => (acc ? acc.and(validator) : validator),
		undefined
	)
}
